"""run_validation.py — batch validate all 20 supplier STL files and produce validation_report.json."""
import json
import math
import sys
import os

# ── vector helpers ──────────────────────────────────────────────────────────
def _cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )

def _sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def _dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def _magnitude(v):
    return math.sqrt(v[0]**2 + v[1]**2 + v[2]**2)

def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0]/m, v[1]/m, v[2]/m)

def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))

# ── STL parser ───────────────────────────────────────────────────────────────
def parse_stl_ascii(path):
    """Parse ASCII STL, return list of (declared_normal, [v1,v2,v3])."""
    triangles = []
    parse_errors = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                parse_errors.append(f"Malformed facet normal at line {i+1}")
                i += 1
                continue
            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vparts = vline.split()
                            try:
                                vertices.append((
                                    float(vparts[1]),
                                    float(vparts[2]),
                                    float(vparts[3])
                                ))
                            except (IndexError, ValueError):
                                parse_errors.append(f"Malformed vertex at line {i+1}")
                        i += 1
            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                parse_errors.append(f"Incomplete triangle near line {i+1}")
            continue
        i += 1
    return triangles, parse_errors

# ── validation checks ────────────────────────────────────────────────────────
def validate_stl(path):
    issues = []
    issue_types = set()

    # ── 1. Parse ──
    triangles, parse_errors = parse_stl_ascii(path)
    issues.extend(parse_errors)
    if parse_errors:
        issue_types.add('parse_error')

    if not triangles:
        issues.append('No valid faces found')
        issue_types.add('no_faces')
        return False, issues, issue_types

    # ── 2. Degenerate triangles ──
    degenerate_count = 0
    for declared_normal, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-10:
            degenerate_count += 1
    if degenerate_count:
        issues.append(f'{degenerate_count} degenerate (zero-area) triangle(s)')
        issue_types.add('degenerate_triangles')

    # ── 3. Inverted / wrong normals ──
    inverted_count = 0
    zero_declared_count = 0
    for declared_normal, verts in triangles:
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        if _magnitude(cross) < 1e-10:
            continue  # degenerate, skip
        winding_normal = _normalize(cross)
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            zero_declared_count += 1
            continue
        similarity = _dot(_normalize(declared_normal), winding_normal)
        if similarity < -0.9:   # clearly inverted
            inverted_count += 1

    if inverted_count:
        issues.append(f'{inverted_count} face(s) with inverted normals relative to winding order')
        issue_types.add('inverted_normals')
    if zero_declared_count:
        issues.append(f'{zero_declared_count} face(s) with zero-length declared normal')
        issue_types.add('zero_normals')

    # ── 4. Manifold / edge checks ──
    edge_count = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j+1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges    = [e for e, c in edge_count.items() if c == 1]
    non_manifold  = [e for e, c in edge_count.items() if c > 2]

    if open_edges:
        issues.append(f'Mesh has {len(open_edges)} open edge(s) — not a closed solid')
        issue_types.add('open_edges')
    if non_manifold:
        issues.append(f'Mesh has {len(non_manifold)} non-manifold edge(s) (shared by >2 faces)')
        issue_types.add('non_manifold_edges')

    valid = len(issues) == 0
    return valid, issues, issue_types

# ── pick the primary reason label ───────────────────────────────────────────
PRIORITY = [
    'no_faces', 'parse_error', 'non_manifold_edges', 'open_edges',
    'inverted_normals', 'degenerate_triangles', 'zero_normals',
]

def primary_reason(issue_types):
    for r in PRIORITY:
        if r in issue_types:
            return r
    return list(issue_types)[0] if issue_types else 'unknown'

# ── main ─────────────────────────────────────────────────────────────────────
results = []
files = [f'supplier_{i:03d}.stl' for i in range(1, 21)]

for fname in files:
    path = fname
    if not os.path.exists(path):
        results.append({'file': fname, 'valid': False, 'reason': 'file_not_found'})
        continue

    valid, issues, issue_types = validate_stl(path)
    if valid:
        results.append({'file': fname, 'valid': True})
    else:
        reason = primary_reason(issue_types)
        results.append({'file': fname, 'valid': False, 'reason': reason, '_issues': issues})
    print(f"{fname}: {'OK' if valid else 'FAIL'} {issues}")

report = {'results': []}
for r in results:
    entry = {'file': r['file'], 'valid': r['valid']}
    if not r['valid']:
        entry['reason'] = r.get('reason', 'unknown')
    report['results'].append(entry)

with open('validation_report.json', 'w') as fh:
    json.dump(report, fh, indent=2)

print('\nReport written to validation_report.json')
print(json.dumps(report, indent=2))

