"""stl_batch_validator.py — batch validate ASCII STL files for manufacturing suitability.

Checks:
  - Parse errors / malformed geometry
  - Degenerate (zero-area) triangles
  - Inverted face normals (declared normal opposes winding-order normal)
  - Open edges (non-closed / non-manifold mesh)
  - Non-manifold edges (shared by more than 2 faces)

Outputs validation_report.json with per-file valid/reason entries.
"""
import json
import math
import os

def _cross(a, b):
    return (a[1]*b[2]-a[2]*b[1], a[2]*b[0]-a[0]*b[2], a[0]*b[1]-a[1]*b[0])

def _sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def _dot(a, b):
    return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]

def _magnitude(v):
    return math.sqrt(v[0]**2+v[1]**2+v[2]**2)

def _normalize(v):
    m = _magnitude(v)
    return v if m < 1e-10 else (v[0]/m, v[1]/m, v[2]/m)

def _triangle_area(v1, v2, v3):
    return 0.5*_magnitude(_cross(_sub(v2,v1),_sub(v3,v1)))

def parse_stl_ascii(path):
    triangles, parse_errors = [], []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                dn = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                parse_errors.append(f'Malformed facet normal at line {i+1}')
                i += 1; continue
            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vp = vline.split()
                            try:
                                vertices.append((float(vp[1]),float(vp[2]),float(vp[3])))
                            except (IndexError, ValueError):
                                parse_errors.append(f'Malformed vertex at line {i+1}')
                        i += 1
            if len(vertices) == 3:
                triangles.append((dn, vertices))
            else:
                parse_errors.append(f'Incomplete triangle near line {i+1}')
            continue
        i += 1
    return triangles, parse_errors

PRIORITY = ['no_faces','parse_error','non_manifold_edges','open_edges',
            'inverted_normals','degenerate_triangles','zero_normals']

def validate_stl(path):
    issues, issue_types = [], set()
    triangles, parse_errors = parse_stl_ascii(path)
    issues.extend(parse_errors)
    if parse_errors: issue_types.add('parse_error')
    if not triangles:
        issues.append('No valid faces found'); issue_types.add('no_faces')
        return False, issues, issue_types
    deg = sum(1 for _,v in triangles if _triangle_area(*v) < 1e-10)
    if deg: issues.append(f'{deg} degenerate triangle(s)'); issue_types.add('degenerate_triangles')
    inv = 0
    for dn, verts in triangles:
        cross = _cross(_sub(verts[1],verts[0]),_sub(verts[2],verts[0]))
        if _magnitude(cross) < 1e-10: continue
        if _magnitude(dn) < 1e-10: continue
        if _dot(_normalize(dn),_normalize(cross)) < -0.9: inv += 1
    if inv: issues.append(f'{inv} inverted normal(s)'); issue_types.add('inverted_normals')
    ec = {}
    for _,verts in triangles:
        r = [tuple(round(x,6) for x in v) for v in verts]
        for j in range(3):
            e = tuple(sorted([r[j],r[(j+1)%3]]))
            ec[e] = ec.get(e,0)+1
    oe = sum(1 for c in ec.values() if c==1)
    nm = sum(1 for c in ec.values() if c>2)
    if oe: issues.append(f'{oe} open edge(s)'); issue_types.add('open_edges')
    if nm: issues.append(f'{nm} non-manifold edge(s)'); issue_types.add('non_manifold_edges')
    return len(issues)==0, issues, issue_types

def primary_reason(it):
    for r in PRIORITY:
        if r in it: return r
    return list(it)[0] if it else 'unknown'

def batch_validate(files, output='validation_report.json'):
    report_results = []
    for fname in files:
        if not os.path.exists(fname):
            report_results.append({'file':fname,'valid':False,'reason':'file_not_found'}); continue
        valid, issues, it = validate_stl(fname)
        entry = {'file':fname,'valid':valid}
        if not valid: entry['reason'] = primary_reason(it)
        report_results.append(entry)
    report = {'results': report_results}
    with open(output,'w') as fh: json.dump(report, fh, indent=2)
    return report

if __name__ == '__main__':
    import sys
    files = sys.argv[1:] or [f'supplier_{i:03d}.stl' for i in range(1,21)]
    r = batch_validate(files)
    print(json.dumps(r, indent=2))

